sql:
SELECT AVG(data_size) AS average_data_size
FROM datasets
WHERE telescope_id = 0 AND year_id = 1;

SELECT file_size
FROM data_files
ORDER BY file_size DESC;

SELECT telescope_name
FROM telescopes
WHERE telescope_id = 1;

SELECT file_path, file_size
FROM data_files
WHERE file_size = (SELECT MAX(file_size) FROM data_files);

